import { describe, expect, it } from 'vitest';

import {
  adist,
  admitOccupancy,
  allTight,
  emptyRoom,
  intraTol,
  mergedOne,
  minMembers,
  OccupancyMaster,
  repOf,
  sepThreshold,
  subfloorOne,
  supported,
  tightness,
  twoPeople,
  wellSeparated,
} from '../src/occupancy-count';

describe('adist / repOf (mirrors adist / repOf)', () => {
  it('adist is the saturating absolute difference and symmetric', () => {
    expect(adist(20, 60)).toBe(40);
    expect(adist(60, 20)).toBe(40);
    expect(adist(22, 20)).toBe(2);
    expect(adist(5, 5)).toBe(0);
  });

  it('repOf is the head, or 0 for the empty cluster', () => {
    expect(repOf([20, 21, 22])).toBe(20);
    expect(repOf([])).toBe(0);
  });
});

describe('gates (tightness / wellSeparated / supported)', () => {
  it('tightness holds when members are within intraTol of the head', () => {
    // [20,21,22] vs head 20: spreads 0,1,2 <= 5
    expect(tightness(intraTol, [20, 21, 22])).toBe(true);
    // [20,21,22,60,61] vs head 20: spread 41 > 5
    expect(tightness(intraTol, [20, 21, 22, 60, 61])).toBe(false);
  });

  it('allTight over both honest occupant clusters', () => {
    expect(allTight(intraTol, twoPeople)).toBe(true);
    expect(allTight(intraTol, mergedOne)).toBe(false);
  });

  it('wellSeparated when reps differ by more than sepThreshold', () => {
    // reps 20 vs 60, gap 40 > 10
    expect(wellSeparated(sepThreshold, twoPeople)).toBe(true);
    // an over-split: reps 20 and 22 within 10
    expect(wellSeparated(sepThreshold, [[20, 21], [22], [60, 61]])).toBe(false);
  });

  it('supported when every cluster clears the member floor', () => {
    // lengths 3,2 >= 2
    expect(supported(minMembers, twoPeople)).toBe(true);
    // length 1 < 2
    expect(supported(minMembers, subfloorOne)).toBe(false);
  });
});

describe('promotion check: admitOccupancy', () => {
  it('admits the honest 2-occupant grouping with count 2', () => {
    const a = admitOccupancy(twoPeople, { intraTol, sepThreshold, minMembers });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.count).toBe(2);
    expect(a.tight).toBe(true);
    expect(a.separated).toBe(true);
    expect(a.supported).toBe(true);
  });

  it('withholds the over-merged 1-cluster proposal (under-count)', () => {
    const a = admitOccupancy(mergedOne, { intraTol, sepThreshold, minMembers });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('over_merge_undercount');
    expect(a.tight).toBe(false);
  });

  it('withholds an over-split proposal (over-count)', () => {
    const overSplit = [[20, 21], [22], [60, 61]];
    const a = admitOccupancy(overSplit, { intraTol, sepThreshold, minMembers });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('over_split_overcount');
    expect(a.separated).toBe(false);
  });

  it('withholds a lone sub-floor cluster (carrier noise, not a person)', () => {
    const a = admitOccupancy(subfloorOne, { intraTol, sepThreshold, minMembers });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('subfloor_fragment');
    expect(a.supported).toBe(false);
  });

  it('reports the empty room as observation_only with count 0', () => {
    const a = admitOccupancy(emptyRoom, { intraTol, sepThreshold, minMembers });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('empty_room');
    expect(a.count).toBe(0);
  });
});

describe('hard negative: one window, count fixed by separation', () => {
  it('the same window admits count 2 and rejects the over-merged count 1', () => {
    expect(
      admitOccupancy(twoPeople, { intraTol, sepThreshold, minMembers }).outcome,
    ).toBe('claim_admitted');
    expect(
      admitOccupancy(mergedOne, { intraTol, sepThreshold, minMembers }).outcome,
    ).toBe('claim_withheld');
  });
});

describe('OccupancyMaster (mirrors occupancy_count_master)', () => {
  it('every boundary witness holds', () => {
    expect(OccupancyMaster.twoPeopleTight).toBe(true);
    expect(OccupancyMaster.mergedOneNotTight).toBe(true);
    expect(OccupancyMaster.twoPeopleSeparated).toBe(true);
    expect(OccupancyMaster.twoPeopleSupported).toBe(true);
    expect(OccupancyMaster.subfloorOneUnsupported).toBe(true);
    expect(OccupancyMaster.twoPeopleAdmitted).toBe(true);
    expect(OccupancyMaster.twoPeopleCount).toBe(true);
    expect(OccupancyMaster.emptyRoomObservationOnly).toBe(true);
    expect(OccupancyMaster.emptyRoomCount).toBe(true);
    expect(OccupancyMaster.overMergeRejected).toBe(true);
    expect(OccupancyMaster.subfloorRejected).toBe(true);
    expect(OccupancyMaster.countFixedBySeparation).toBe(true);
  });

  it('uses the Lean fixture numbers (intraTol 5, sep 10, minMembers 2, window)', () => {
    expect(intraTol).toBe(5);
    expect(sepThreshold).toBe(10);
    expect(minMembers).toBe(2);
    expect(twoPeople).toEqual([[20, 21, 22], [60, 61]]);
    expect(mergedOne).toEqual([[20, 21, 22, 60, 61]]);
  });
});
